import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import MicrosoftTeams from './components/MicrosoftTeams';
import Zoom from './components/Zoom';
import Skype from './components/Skype';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/chrome';
import FileExplorer from './components/FileExplorer';
import './App.css';

const App = () => {
  const [activeComponent, setActiveComponent] = useState(null);

  return (
    <Router>
      <div className="App">
        <Sidebar setActiveComponent={setActiveComponent} />
        <div className="content">
          {/* Folosim router-ul doar pentru Teams, Zoom, și Skype */}
          <Routes>
            <Route path="/teams" element={<MicrosoftTeams />} />
            <Route path="/zoom" element={<Zoom />} />
            <Route path="/skype" element={<Skype />} />
          </Routes>

          {/* Folosim activeComponent pentru restul componentelor */}
          {activeComponent === 'fileExplorer' && <FileExplorer />}
          {activeComponent === 'microsoftWord' && <MicrosoftWord />}
          {activeComponent === 'microsoftExcel' && <MicrosoftExcel />}
          {activeComponent === 'powerPoint' && <PowerPoint />}
          {activeComponent === 'pdfReader' && <PDFReader />}
          {activeComponent === 'chrome' && <Chrome />}
        </div>
      </div>
    </Router>
  );
};

export default App;
